Rule.Source:
  import sailpoint.object.Filter;
  import sailpoint.object.Application;
  import sailpoint.object.Custom;

  Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-PhysicianEntitlement");
  List entitlements = new ArrayList();

  if(custom!=null ){
    if(custom.get("Non-ProductionCerner-ServiceNow-Entitlements") != null){
      entitlements.addAll(custom.get("Non-ProductionCerner-ServiceNow-Entitlements"));
    }
    if(custom.get("Cerner-ServiceNow-Entitlements") != null){
      entitlements.addAll(custom.get("Cerner-ServiceNow-Entitlements"));
    }    
  }

  return Filter.or(Filter.and(Filter.ignoreCase(Filter.eq("application.name", "Cerner-Service Now")),Filter.ignoreCase(Filter.in("value",entitlements))),
                   Filter.and(Filter.ignoreCase(Filter.eq("application.name", "Non-Production Cerner-Service Now")),Filter.ignoreCase(Filter.in("value",entitlements))));
